import { verifyUser } from '@/lib/auth'
import { getBalance, debitUsage } from '@/lib/supabase-admin'

// Proxy de chat completions (OpenAI-compatible), streaming pass-through.
// Fluxo: verifica JWT → checa saldo → injeta a chave real → repassa o SSE da
// OpenRouter ao app, lendo o `usage.cost` do chunk final para debitar no fim.
export const runtime = 'edge'

const OPENROUTER = 'https://openrouter.ai/api/v1'
const CORS = {
  'Access-Control-Allow-Origin': process.env.CORS_ORIGIN || '*',
  'Access-Control-Allow-Headers': 'authorization, content-type',
  'Access-Control-Allow-Methods': 'POST, OPTIONS',
}

export function OPTIONS(): Response {
  return new Response(null, { status: 204, headers: CORS })
}

function json(status: number, body: unknown): Response {
  return new Response(JSON.stringify(body), {
    status,
    headers: { 'Content-Type': 'application/json', ...CORS },
  })
}

interface Usage {
  cost?: number
  prompt_tokens?: number
  completion_tokens?: number
}

export async function POST(req: Request): Promise<Response> {
  // 1) Autenticação (local, sem tocar o Supabase).
  let userId: string
  try {
    userId = await verifyUser(req.headers.get('authorization'))
  } catch {
    return json(401, { error: { message: 'não autenticado', type: 'auth' } })
  }

  // 2) Gate de saldo — protege a chave antes de qualquer chamada à OpenRouter.
  try {
    const balance = await getBalance(userId)
    if (!(balance > 0)) {
      return json(402, { error: { message: 'créditos esgotados', type: 'insufficient_credits' } })
    }
  } catch (e) {
    return json(502, { error: { message: `falha ao checar saldo: ${(e as Error).message}`, type: 'upstream' } })
  }

  // 3) Corpo: força streaming + pede o custo (usage.include) à OpenRouter.
  let body: Record<string, unknown>
  try {
    body = await req.json()
  } catch {
    return json(400, { error: { message: 'corpo inválido', type: 'bad_request' } })
  }
  body.stream = true
  body.usage = { include: true }
  const model = typeof body.model === 'string' ? body.model : null

  // 4) Encaminha à OpenRouter com a chave real (só existe aqui).
  const key = process.env.OPENROUTER_KEY
  if (!key) return json(500, { error: { message: 'OPENROUTER_KEY ausente', type: 'config' } })

  const upstream = await fetch(`${OPENROUTER}/chat/completions`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${key}`,
      'HTTP-Referer': 'https://axyoma-ai.app',
      'X-Title': 'AXYOMA AI',
    },
    body: JSON.stringify(body),
  })

  if (!upstream.ok || !upstream.body) {
    const detail = await upstream.text().catch(() => '')
    return json(upstream.status || 502, {
      error: { message: `openrouter: ${detail || upstream.statusText}`, type: 'upstream' },
    })
  }

  // 5) Tee do SSE: repassa cada chunk ao app e vai lendo o último `usage` visto.
  const reader = upstream.body.getReader()
  const decoder = new TextDecoder()
  let buffer = ''
  let lastUsage: Usage | null = null

  const scan = (text: string): void => {
    buffer += text
    let nl: number
    while ((nl = buffer.indexOf('\n')) !== -1) {
      const line = buffer.slice(0, nl).trim()
      buffer = buffer.slice(nl + 1)
      if (!line.startsWith('data:')) continue
      const payload = line.slice(5).trim()
      if (payload === '[DONE]') continue
      try {
        const obj = JSON.parse(payload)
        if (obj && obj.usage) lastUsage = obj.usage as Usage
      } catch {
        /* chunk parcial/keepalive — ignora */
      }
    }
  }

  const stream = new ReadableStream<Uint8Array>({
    async pull(controller) {
      const { done, value } = await reader.read()
      if (done) {
        // Débito no fim do stream (mesma invocação). Falha aqui não quebra a
        // resposta já entregue — apenas loga; reconciliação via usage_log.
        try {
          if (lastUsage && typeof lastUsage.cost === 'number' && lastUsage.cost >= 0) {
            await debitUsage({
              userId,
              costUsd: lastUsage.cost,
              model,
              promptTokens: lastUsage.prompt_tokens,
              completionTokens: lastUsage.completion_tokens,
            })
          }
        } catch (e) {
          console.error('debit falhou', (e as Error).message)
        }
        controller.close()
        return
      }
      controller.enqueue(value)
      scan(decoder.decode(value, { stream: true }))
    },
    cancel() {
      reader.cancel().catch(() => {})
    },
  })

  return new Response(stream, {
    status: 200,
    headers: {
      'Content-Type': 'text/event-stream; charset=utf-8',
      'Cache-Control': 'no-cache, no-transform',
      Connection: 'keep-alive',
      ...CORS,
    },
  })
}

import { verifyUser } from '@/lib/auth'

// Catálogo de modelos — pass-through do catálogo da OpenRouter. Exige JWT válido
// para não deixar o proxy aberto. O app passa a listar modelos por aqui em vez
// de bater direto em openrouter.ai.
export const runtime = 'edge'

const OPENROUTER = 'https://openrouter.ai/api/v1'
const CORS = {
  'Access-Control-Allow-Origin': process.env.CORS_ORIGIN || '*',
  'Access-Control-Allow-Headers': 'authorization, content-type',
  'Access-Control-Allow-Methods': 'GET, OPTIONS',
}

export function OPTIONS(): Response {
  return new Response(null, { status: 204, headers: CORS })
}

export async function GET(req: Request): Promise<Response> {
  try {
    await verifyUser(req.headers.get('authorization'))
  } catch {
    return new Response(JSON.stringify({ error: { message: 'não autenticado' } }), {
      status: 401,
      headers: { 'Content-Type': 'application/json', ...CORS },
    })
  }

  const key = process.env.OPENROUTER_KEY
  const upstream = await fetch(`${OPENROUTER}/models`, {
    headers: key ? { Authorization: `Bearer ${key}` } : {},
  })

  return new Response(upstream.body, {
    status: upstream.status,
    headers: { 'Content-Type': 'application/json', 'Cache-Control': 'public, max-age=300', ...CORS },
  })
}

'use client'

import { useEffect, useState, useCallback } from 'react'
import { useRouter } from 'next/navigation'
import Link from 'next/link'
import {
  LayoutDashboard,
  Receipt,
  BookOpen,
  LogOut,
  Download,
  Wallet,
  CalendarDays,
  TrendingUp,
  BadgeCheck,
} from 'lucide-react'
import { supabase, SUPABASE_URL } from '@/lib/supabase-browser'
import { AxiomaLogo } from '@/components/AxiomaLogo'

type UsageRow = { ts: string; model: string | null; credits: number; kind: string; prompt_tokens: number; completion_tokens: number }

function dayKey(iso: string): string {
  return iso.slice(0, 10)
}
function fmt(n: number): string {
  return n.toLocaleString('pt-BR', { maximumFractionDigits: 2 })
}

export default function ContaPage(): React.JSX.Element {
  const router = useRouter()
  const [loading, setLoading] = useState(true)
  const [email, setEmail] = useState('')
  const [name, setName] = useState('')
  const [balance, setBalance] = useState(0)
  const [purchased, setPurchased] = useState(0)
  const [plan, setPlan] = useState('Free')
  const [rows, setRows] = useState<UsageRow[]>([])
  const [buying, setBuying] = useState(false)
  const [now, setNow] = useState(0)

  const load = useCallback(async () => {
    const { data: sess } = await supabase.auth.getSession()
    const user = sess.session?.user
    if (!user) {
      router.replace('/login')
      return
    }
    setEmail(user.email ?? '')
    const [profileRes, credRes, subRes, usageRes] = await Promise.all([
      supabase.from('profiles').select('full_name').eq('id', user.id).maybeSingle(),
      supabase.from('credits').select('balance, total_purchased').eq('user_id', user.id).maybeSingle(),
      supabase.from('subscriptions').select('status, plans(name)').eq('owner_user_id', user.id).eq('status', 'active').maybeSingle(),
      supabase.from('usage_log').select('ts, model, credits, kind, prompt_tokens, completion_tokens').eq('user_id', user.id).order('ts', { ascending: false }).limit(300),
    ])
    setName(profileRes.data?.full_name ?? '')
    setBalance(Number(credRes.data?.balance ?? 0))
    setPurchased(Number(credRes.data?.total_purchased ?? 0))
    setPlan((subRes.data as { plans?: { name?: string } } | null)?.plans?.name ?? 'Free')
    setRows((usageRes.data as UsageRow[]) ?? [])
    setNow(Date.now())
    setLoading(false)
  }, [router])

  // Fetch de sessão + agregados ao montar (cliente).
  useEffect(() => {
    // Client-only data load on mount; setState happens after async I/O.
    // eslint-disable-next-line react-hooks/set-state-in-effect -- intentional client data fetch
    void load()
  }, [load])

  async function buyCredits(): Promise<void> {
    setBuying(true)
    try {
      const { data } = await supabase.auth.getSession()
      const token = data.session?.access_token
      if (!token) return
      const res = await fetch(`${SUPABASE_URL}/functions/v1/abacatepay-create-checkout`, {
        method: 'POST',
        headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' },
        body: JSON.stringify({ packId: 'credits-100' }),
      })
      const json = await res.json().catch(() => null)
      if (json?.url) window.open(json.url as string, '_blank')
      else alert(json?.error ?? 'Falha ao criar checkout.')
    } finally {
      setBuying(false)
    }
  }

  async function signOut(): Promise<void> {
    await supabase.auth.signOut()
    router.replace('/')
  }

  if (loading) {
    return <main className="flex min-h-screen items-center justify-center bg-neutral-950 text-sm text-neutral-400">Carregando…</main>
  }

  // Agregações (now capturado ao carregar dados)
  const today = new Date(now).toISOString().slice(0, 10)
  const spentToday = rows.filter((r) => dayKey(r.ts) === today).reduce((a, r) => a + Number(r.credits), 0)
  const spent30 = rows.filter((r) => now - new Date(r.ts).getTime() < 30 * 864e5).reduce((a, r) => a + Number(r.credits), 0)

  // Últimos 14 dias (custo diário)
  const days: { label: string; total: number }[] = []
  for (let i = 13; i >= 0; i--) {
    const d = new Date(now - i * 864e5)
    const key = d.toISOString().slice(0, 10)
    const total = rows.filter((r) => dayKey(r.ts) === key).reduce((a, r) => a + Number(r.credits), 0)
    days.push({ label: String(d.getDate()), total })
  }
  const maxDay = Math.max(0.001, ...days.map((d) => d.total))

  return (
    <div className="flex min-h-screen bg-neutral-950 text-neutral-100">
      {/* Sidebar */}
      <aside className="hidden w-60 shrink-0 flex-col border-r border-neutral-800 bg-neutral-900/50 p-4 md:flex">
        <Link href="/" className="mb-8 flex items-center gap-2 px-2">
          <AxiomaLogo id="side" className="h-7 w-7" />
          <span className="font-brand text-lg italic">Axyoma</span>
        </Link>
        <nav className="flex flex-1 flex-col gap-1 text-sm">
          <a href="#visao" className="flex items-center gap-2.5 rounded-lg bg-neutral-800 px-3 py-2 font-medium"><LayoutDashboard className="size-4" /> Visão geral</a>
          <a href="#uso" className="flex items-center gap-2.5 rounded-lg px-3 py-2 text-neutral-400 transition-colors hover:bg-neutral-800 hover:text-neutral-100"><Receipt className="size-4" /> Uso</a>
          <a href="#docs" className="flex items-center gap-2.5 rounded-lg px-3 py-2 text-neutral-400 transition-colors hover:bg-neutral-800 hover:text-neutral-100"><BookOpen className="size-4" /> Documentação</a>
        </nav>
        <button onClick={signOut} className="flex items-center gap-2.5 rounded-lg px-3 py-2 text-sm text-neutral-400 transition-colors hover:bg-neutral-800 hover:text-neutral-100">
          <LogOut className="size-4" /> Sair
        </button>
      </aside>

      {/* Main */}
      <main className="mx-auto w-full max-w-4xl flex-1 px-6 py-8">
        {/* Header */}
        <div className="mb-8 flex items-center justify-between">
          <div>
            <h1 className="text-2xl font-semibold">Olá, {name || email.split('@')[0]}</h1>
            <p className="text-sm text-neutral-400">{email}</p>
          </div>
          <div className="flex items-center gap-2 rounded-full border border-neutral-800 bg-neutral-900 px-3 py-1.5 text-xs">
            <BadgeCheck className="size-3.5 text-amber-500" /> Plano {plan}
          </div>
        </div>

        {/* KPIs */}
        <section id="visao" className="mb-6 grid grid-cols-2 gap-4 lg:grid-cols-4">
          <Kpi icon={<Wallet className="size-4" />} label="Saldo" value={fmt(balance)} sub={`≈ R$ ${fmt(balance * 0.3)}`} accent />
          <Kpi icon={<CalendarDays className="size-4" />} label="Gasto hoje" value={fmt(spentToday)} sub="créditos" />
          <Kpi icon={<TrendingUp className="size-4" />} label="Gasto (30d)" value={fmt(spent30)} sub="créditos" />
          <Kpi icon={<Receipt className="size-4" />} label="Total comprado" value={fmt(purchased)} sub="créditos" />
        </section>

        {/* Comprar + custo diário */}
        <div className="mb-6 grid gap-4 lg:grid-cols-3">
          <div className="flex flex-col justify-between rounded-2xl border border-neutral-800 bg-neutral-900 p-6">
            <div>
              <p className="text-sm text-neutral-400">Precisa de mais?</p>
              <p className="mt-1 text-lg font-semibold">Comprar créditos</p>
              <p className="mt-1 text-xs text-neutral-500">Pague via PIX. 1 crédito = R$ 0,30.</p>
            </div>
            <button onClick={buyCredits} disabled={buying} className="brand-gradient mt-5 rounded-full py-2.5 text-sm font-semibold text-black transition-transform hover:scale-[1.02] disabled:opacity-60">
              {buying ? 'Abrindo…' : 'Comprar créditos'}
            </button>
          </div>

          <div className="rounded-2xl border border-neutral-800 bg-neutral-900 p-6 lg:col-span-2">
            <p className="mb-4 text-sm font-semibold">Custo diário (14 dias)</p>
            <div className="flex h-32 items-end gap-1.5">
              {days.map((d, i) => (
                <div key={i} className="group flex flex-1 flex-col items-center gap-1.5">
                  <div className="relative flex w-full flex-1 items-end">
                    <div
                      className="w-full rounded-t bg-gradient-to-t from-amber-600/40 to-amber-400 transition-all"
                      style={{ height: `${Math.max(2, (d.total / maxDay) * 100)}%` }}
                      title={`${fmt(d.total)} créditos`}
                    />
                  </div>
                  <span className="text-[10px] text-neutral-500">{d.label}</span>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Uso recente */}
        <section id="uso" className="mb-6 rounded-2xl border border-neutral-800 bg-neutral-900 p-6">
          <p className="mb-4 text-sm font-semibold">Uso recente</p>
          {rows.length === 0 ? (
            <p className="text-sm text-neutral-500">Nenhum uso ainda.</p>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-left text-sm">
                <thead className="text-xs text-neutral-500">
                  <tr className="border-b border-neutral-800">
                    <th className="pb-2 font-medium">Modelo</th>
                    <th className="pb-2 text-right font-medium">Tokens</th>
                    <th className="pb-2 text-right font-medium">Créditos</th>
                    <th className="hidden pb-2 text-right font-medium sm:table-cell">Data</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-neutral-800/70">
                  {rows.slice(0, 12).map((r, i) => (
                    <tr key={i} className="text-neutral-300">
                      <td className="py-2.5 font-mono text-xs">{r.model ?? r.kind}</td>
                      <td className="py-2.5 text-right text-neutral-400">{fmt((r.prompt_tokens ?? 0) + (r.completion_tokens ?? 0))}</td>
                      <td className="py-2.5 text-right">−{fmt(Number(r.credits))}</td>
                      <td className="hidden py-2.5 text-right text-neutral-500 sm:table-cell">
                        {new Date(r.ts).toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' })}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </section>

        {/* Documentação */}
        <section id="docs" className="mb-6 rounded-2xl border border-neutral-800 bg-neutral-900 p-6">
          <p className="mb-4 text-sm font-semibold">Documentação</p>
          <div className="grid gap-3 sm:grid-cols-3">
            {[
              { t: 'Começando', d: 'Instale e faça login.', href: '/docs' },
              { t: 'Créditos', d: 'Como funciona a cobrança.', href: '/docs' },
              { t: 'Os três modos', d: 'Design, Plan e Code.', href: '/docs' },
            ].map((doc) => (
              <a key={doc.t} href={doc.href} className="rounded-xl border border-neutral-800 bg-neutral-950 p-4 transition-colors hover:border-neutral-700">
                <p className="text-sm font-medium">{doc.t}</p>
                <p className="mt-1 text-xs text-neutral-500">{doc.d}</p>
              </a>
            ))}
          </div>
        </section>

        <div className="flex items-center justify-between text-sm text-neutral-500">
          <Link href="/download" className="flex items-center gap-1.5 text-amber-500 hover:underline">
            <Download className="size-4" /> Baixar o app
          </Link>
          <button onClick={signOut} className="md:hidden">Sair</button>
        </div>
      </main>
    </div>
  )
}

function Kpi({ icon, label, value, sub, accent }: { icon: React.ReactNode; label: string; value: string; sub: string; accent?: boolean }): React.JSX.Element {
  return (
    <div className="rounded-2xl border border-neutral-800 bg-neutral-900 p-4">
      <div className="mb-2 flex items-center gap-2 text-xs text-neutral-400">
        <span className="text-neutral-500">{icon}</span> {label}
      </div>
      <p className={`text-2xl font-semibold ${accent ? 'brand-text' : ''}`}>{value}</p>
      <p className="mt-0.5 text-xs text-neutral-500">{sub}</p>
    </div>
  )
}

'use client'

import { useSyncExternalStore } from 'react'
import Link from 'next/link'
import Image from 'next/image'
import { AxiomaLogo } from '@/components/AxiomaLogo'
import { StarField } from '@/components/StarField'

// ============================================================
// COLOQUE AQUI OS LINKS DIRETOS PARA OS INSTALÁVEIS (não o repositório).
// Exemplo: .dmg, .exe, .AppImage, .deb, etc.
// ============================================================
const DOWNLOAD_LINKS = {
  mac:   'https://github.com/BryanLinocnl/AXIOMA-AI-releases/releases/download/v0.1.2/AXYOMA.AI-0.1.2-arm64.dmg',
  win:   'https://github.com/BryanLinocnl/AXIOMA-AI-releases/releases/download/v0.1.2/AXYOMA.AI-0.1.2-setup.exe',
  linux: 'https://github.com/BryanLinocnl/AXIOMA-AI-releases/releases/download/v0.1.2/AXYOMA.AI-0.1.2.AppImage',
} as const

const RELEASES = 'https://github.com/BryanLinocnl/AXIOMA-AI-releases/releases/latest'

type OS = 'mac' | 'win' | 'linux' | 'other'

function detectOS(): OS {
  if (typeof navigator === 'undefined') return 'other'
  const p = `${navigator.platform} ${navigator.userAgent}`.toLowerCase()
  if (p.includes('mac')) return 'mac'
  if (p.includes('win')) return 'win'
  if (p.includes('linux') || p.includes('x11')) return 'linux'
  return 'other'
}

function subscribe(): () => void {
  return () => {}
}

function useOS(): OS {
  return useSyncExternalStore(subscribe, detectOS, () => 'other' as OS)
}

function MacIcon({ className }: { className?: string }) {
  return (
    <Image
      src="/apple-logo-svgrepo-com.svg"
      alt=""
      width={20}
      height={20}
      unoptimized
      className={className}
      aria-hidden="true"
    />
  )
}

function WindowsIcon({ className }: { className?: string }) {
  return (
    <svg viewBox="0 0 24 24" fill="currentColor" className={className} aria-hidden="true">
      <path d="M0 3.45L9.89 1.98L9.89 11.26L0 11.26L0 3.45ZM10.74 11.26L24 11.26L24 0L10.74 1.63L10.74 11.26ZM0 12.74L9.89 12.74L9.89 22.02L0 20.55L0 12.74ZM10.74 12.74L10.74 22.37L24 24L24 12.74L10.74 12.74Z" />
    </svg>
  )
}

function LinuxIcon({ className }: { className?: string }) {
  return (
    <Image
      src="/linux-svgrepo-com.svg"
      alt=""
      width={20}
      height={20}
      unoptimized
      className={className}
      aria-hidden="true"
    />
  )
}

type TargetOS = keyof typeof DOWNLOAD_LINKS

const BUTTONS: { key: TargetOS; label: string; icon: React.FC<{ className?: string }> }[] = [
  { key: 'mac', label: 'Baixar para macOS', icon: MacIcon },
  { key: 'win', label: 'Baixar para Windows', icon: WindowsIcon },
  { key: 'linux', label: 'Baixar para Linux', icon: LinuxIcon },
]

export default function DownloadPage(): React.JSX.Element {
  const os = useOS()

  return (
    <main className="relative flex min-h-screen flex-col items-center justify-center overflow-hidden px-6 text-center">
      <StarField />
      <div className="relative z-10 flex flex-col items-center">
        <Link href="/" className="mb-8 flex items-center gap-2">
          <AxiomaLogo id="dl" className="h-8 w-8" />
          <span className="font-brand text-xl italic">Axyoma</span>
        </Link>

        <h1 className="text-3xl font-semibold tracking-tight sm:text-4xl">
          Baixe o <span className="font-brand italic brand-text">Axyoma IA</span>
        </h1>
        <p className="mt-3 max-w-md text-sm text-[var(--ink-dim)]">
          Grátis. Crie sua conta e ganhe 100 créditos para começar.
        </p>

        <div className="mt-8 flex flex-col gap-3 sm:flex-row sm:items-center">
          {BUTTONS.map(({ key, label, icon: Icon }) => {
            const isDetected = os === key
            return (
              <a
                key={key}
                href={DOWNLOAD_LINKS[key as TargetOS]}
                target="_blank"
                rel="noreferrer"
                className={`brand-gradient inline-flex items-center justify-center gap-2.5 rounded-full px-6 py-3 text-sm font-semibold text-black shadow-lg shadow-orange-600/25 transition-transform hover:scale-[1.03] ${isDetected ? 'ring-2 ring-white/40' : ''}`}
                aria-label={label}
              >
                <Icon className="h-4 w-4" />
                {isDetected ? 'Baixar para este dispositivo' : label}
              </a>
            )
          })}
        </div>

        <p className="mt-6 text-xs text-[var(--ink-faint)]">
          Não sabe qual é o seu sistema?{' '}
          <a href={RELEASES} target="_blank" rel="noreferrer" className="underline">Veja todas as versões</a>
        </p>

        <p className="mt-8 text-xs text-[var(--ink-faint)]">
          Já tem o app? <Link href="/conta" className="underline">Acesse sua conta</Link>
        </p>
      </div>
    </main>
  )
}

@import 'tailwindcss';

/* AXYOMA landing — craft material, brand amber→red, tipografia de ofício.
   Hero centralizada com logo em destaque e efeito de borda/aurora. */

:root {
  --brand-1: #fcb31b;
  --brand-2: #fb860a;
  --brand-3: #f6400e;
  --brand-4: #e32111;
  --ink: #ececf1;
  --ink-dim: #a1a1aa;
  --ink-faint: #6b6b74;
  --bg: #050506;
  --border: rgba(255, 255, 255, 0.1);
  --border-soft: rgba(255, 255, 255, 0.08);
  --surface: rgba(255, 255, 255, 0.02);
  --surface-hover: rgba(255, 255, 255, 0.04);
}

* {
  box-sizing: border-box;
}

:focus-visible {
  outline: 2px solid var(--brand-1);
  outline-offset: 3px;
}

html {
  scroll-behavior: smooth;
}

body {
  margin: 0;
  min-height: 100vh;
  color: var(--ink);
  background: var(--bg);
  font-family: var(--font-bricolage), system-ui, sans-serif;
  font-optical-sizing: auto;
  font-variation-settings: 'wdth' 100;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

.font-display,
.font-brand,
.brand-italic {
  font-family: var(--font-playfair), Georgia, 'Times New Roman', serif;
  font-style: italic;
}

.font-mono {
  font-family: var(--font-jetbrains), ui-monospace, SFMono-Regular, Menlo, monospace;
}

.brand-gradient {
  background: linear-gradient(135deg, #fcb31b 0%, #fb860a 45%, #f6400e 75%, #e32111 100%);
}

.brand-text {
  background: linear-gradient(135deg, #fcb31b 0%, #fb860a 45%, #f6400e 75%, #e32111 100%);
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
}

/* Rising entrance used sparingly on first paint */
@keyframes ax-rise {
  0% {
    transform: translateY(20px);
    opacity: 0;
  }
  100% {
    transform: translateY(0);
    opacity: 1;
  }
}

.ax-rise {
  animation: ax-rise 0.7s cubic-bezier(0.2, 0.7, 0.2, 1) both;
}

/* Subtle brand glow for nav / mock accents */
.ax-glow {
  box-shadow: 0 0 48px -16px rgba(246, 64, 14, 0.35);
}

/* Glass nav */
.ax-nav-glass {
  background: rgba(5, 5, 6, 0.72);
  backdrop-filter: blur(16px) saturate(1.2);
  -webkit-backdrop-filter: blur(16px) saturate(1.2);
  border-bottom: 1px solid var(--border-soft);
}

/* Product mock chrome */
.ax-mock {
  background: linear-gradient(180deg, #0c0c0f 0%, #070708 100%);
  border: 1px solid rgba(255, 255, 255, 0.1);
  box-shadow:
    0 0 0 1px rgba(0, 0, 0, 0.4),
    0 40px 80px -24px rgba(0, 0, 0, 0.85),
    0 0 60px -20px rgba(246, 64, 14, 0.18);
}

/* Soft amber vignette — hero only, not full-page wallpaper */
.ax-hero-vignette {
  background:
    radial-gradient(70% 55% at 50% 0%, rgba(251, 134, 10, 0.12), transparent 55%),
    radial-gradient(50% 40% at 50% 0%, rgba(252, 179, 27, 0.06), transparent 50%);
}

/* Starfield: contained within the hero, not aggressive full-page wallpaper */
.ax-star {
  position: absolute;
  border-radius: 9999px;
  animation: ax-twinkle var(--dur, 4s) ease-in-out var(--delay, 0s) infinite;
  will-change: opacity;
}

@keyframes ax-twinkle {
  0%, 100% {
    opacity: 0.15;
  }
  50% {
    opacity: 0.9;
  }
}

/* Hero logo stage: conic border beams + halo glow, matching original */
.ax-stage {
  position: relative;
  overflow: hidden;
  border-radius: 30px;
  padding: 1px;
  animation: ax-breathe 4.5s ease-in-out infinite;
}

@keyframes ax-breathe {
  0%, 100% {
    box-shadow: 0 0 42px -14px rgba(246, 64, 14, 0.4);
  }
  50% {
    box-shadow: 0 0 72px -10px rgba(252, 179, 27, 0.5);
  }
}

.ax-beam,
.ax-beam-rev {
  position: absolute;
  inset: -50%;
  border-radius: 50%;
  pointer-events: none;
}

.ax-beam {
  background: conic-gradient(
    transparent 0deg 275deg,
    rgba(252, 179, 27, 0.95) 318deg,
    rgba(246, 64, 14, 0.95) 342deg,
    transparent 360deg
  );
  animation: ax-orbit 4.2s linear infinite;
}

.ax-beam-rev {
  opacity: 0;
  background: conic-gradient(
    from 180deg,
    transparent 0deg 285deg,
    rgba(251, 134, 10, 0.9) 325deg,
    rgba(227, 33, 17, 0.9) 348deg,
    transparent 360deg
  );
  animation: ax-orbit-rev 3s linear infinite;
  transition: opacity 0.35s ease;
}

.ax-halo {
  position: absolute;
  inset: -18px;
  border-radius: 40px;
  filter: blur(18px);
  opacity: 0.35;
  background: conic-gradient(
    transparent 0deg 275deg,
    rgba(252, 179, 27, 0.8) 318deg,
    rgba(246, 64, 14, 0.8) 342deg,
    transparent 360deg
  );
  animation: ax-orbit 4.2s linear infinite;
  transition: opacity 0.35s ease;
  pointer-events: none;
}

@keyframes ax-orbit {
  to {
    transform: rotate(1turn);
  }
}

@keyframes ax-orbit-rev {
  to {
    transform: rotate(-1turn);
  }
}

.ax-hover:hover .ax-beam-rev {
  opacity: 1;
}

.ax-hover:hover .ax-halo {
  opacity: 0.8;
}

@media (prefers-reduced-motion: reduce) {
  .ax-rise,
  .ax-stage,
  .ax-star {
    animation: none;
  }

  html {
    scroll-behavior: auto;
  }

  .ax-stage {
    box-shadow: 0 0 48px -12px rgba(246, 64, 14, 0.4);
  }

  .ax-beam,
  .ax-beam-rev,
  .ax-halo {
    display: none;
  }
}

