import { jwtVerify, createRemoteJWKSet, type JWTVerifyGetKey } from 'jose'

// Verificação de JWT do Supabase feita LOCALMENTE (sem round-trip ao Supabase
// no hot path). Suporta os dois modos de assinatura:
//  - HS256 (legado): usa o SUPABASE_JWT_SECRET.
//  - ES256/RS256 (assimétrico): usa a JWKS pública do projeto (cacheada por jose).

const SUPABASE_URL = process.env.SUPABASE_URL
const JWT_SECRET = process.env.SUPABASE_JWT_SECRET

let jwks: JWTVerifyGetKey | null = null
function getJwks(): JWTVerifyGetKey {
  if (!SUPABASE_URL) throw new Error('SUPABASE_URL ausente')
  if (!jwks) {
    jwks = createRemoteJWKSet(new URL(`${SUPABASE_URL}/auth/v1/.well-known/jwks.json`))
  }
  return jwks
}

/** Retorna o user id (claim `sub`) se o token for válido; lança se inválido/expirado. */
export async function verifyUser(authHeader: string | null): Promise<string> {
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    throw new Error('authorization ausente')
  }
  const token = authHeader.slice(7).trim()

  const { payload } = JWT_SECRET
    ? await jwtVerify(token, new TextEncoder().encode(JWT_SECRET))
    : await jwtVerify(token, getJwks())

  const sub = payload.sub
  if (!sub || typeof sub !== 'string') throw new Error('sub ausente')
  return sub
}

// Chamadas administrativas ao Postgres via PostgREST RPC, com a service-role key.
// Fetch puro (sem SDK) para rodar no runtime edge. Nunca exponha estas funções
// sem antes verificar o JWT do usuário na rota.

const SUPABASE_URL = process.env.SUPABASE_URL
const SERVICE_ROLE = process.env.SUPABASE_SERVICE_ROLE_KEY

function assertEnv(): { url: string; key: string } {
  if (!SUPABASE_URL || !SERVICE_ROLE) throw new Error('SUPABASE_URL/SERVICE_ROLE_KEY ausentes')
  return { url: SUPABASE_URL, key: SERVICE_ROLE }
}

async function rpc<T>(fn: string, args: Record<string, unknown>): Promise<T> {
  const { url, key } = assertEnv()
  const res = await fetch(`${url}/rest/v1/rpc/${fn}`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      apikey: key,
      Authorization: `Bearer ${key}`,
    },
    body: JSON.stringify(args),
  })
  if (!res.ok) {
    const detail = await res.text().catch(() => '')
    throw new Error(`rpc ${fn} falhou (${res.status}): ${detail}`)
  }
  return (await res.json()) as T
}

/** Saldo atual do usuário (gate pré-request). Retorna número (créditos). */
export async function getBalance(userId: string): Promise<number> {
  const v = await rpc<number>('get_balance_admin', { p_user: userId })
  return typeof v === 'number' ? v : Number(v ?? 0)
}

/** Debita o custo real (USD) do turno; a conversão p/ créditos é feita no banco. */
export async function debitUsage(params: {
  userId: string
  costUsd: number
  model?: string | null
  promptTokens?: number
  completionTokens?: number
}): Promise<void> {
  await rpc('spend_openrouter_usage_admin', {
    p_user: params.userId,
    p_cost_usd: params.costUsd,
    p_model: params.model ?? null,
    p_prompt_tokens: params.promptTokens ?? 0,
    p_completion_tokens: params.completionTokens ?? 0,
  })
}

import { createClient } from '@supabase/supabase-js'

// Cliente Supabase do navegador (landing). Anon key é pública. Sessão fica no
// localStorage; OAuth usa PKCE com detecção do code na URL de retorno.
export const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL as string,
  process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY as string,
  {
    auth: {
      persistSession: true,
      autoRefreshToken: true,
      detectSessionInUrl: true,
      flowType: 'pkce',
    },
  }
)

export const SUPABASE_URL = process.env.NEXT_PUBLIC_SUPABASE_URL as string

